/**
 * Blog topics — the curated set of SEO articles the content engine generates.
 * Each targets a real, high-intent search query and links to relevant /analysis
 * pages (internal linking + a funnel into the product). Content is generated by
 * Claude and cached; these entries define WHAT to write and which tickers to
 * cross-link (kept deterministic here rather than trusting the model).
 */

import type { AssetId } from '@/lib/data/types';

export interface BlogTopic {
  slug: string;
  title: string;
  /** Primary keyword/intent — steers the generation prompt. */
  keyword: string;
  category: 'Comparisons' | 'Investing Basics' | 'Stock Questions' | 'Guides';
  /** Assets to cross-link to their /analysis pages. */
  related: AssetId[];
}

