export function findTopic(slug: string): BlogTopic | undefined {
  return BLOG_TOPICS.find((t) => t.slug === slug);
}

export function groupedTopics(): Array<{ category: string; topics: BlogTopic[] }> {
  const order: string[] = [];
  const map = new Map<string, BlogTopic[]>();
  for (const t of BLOG_TOPICS) {
    if (!map.has(t.category)) { map.set(t.category, []); order.push(t.category); }
    map.get(t.category)!.push(t);
  }
  return order.map((category) => ({ category, topics: map.get(category)! }));
}
